(function(w){class P{constructor(){this.ready=false;this.q=[];this.init()}async init(){console.log('PYTML: Loading...');this.showStatus();try{if(typeof loadPyodide==='undefined'){await this.loadScript('https://cdn.jsdelivr.net/pyodide/v0.24.1/full/pyodide.js')}this.pyodide=await loadPyodide({indexURL:'https://cdn.jsdelivr.net/pyodide/v0.24.1/full/'});this.ready=true;console.log('PYTML: Ready!');this.hideStatus();this.q.forEach(c=>c());this.q=[];this.processPage()}catch(e){this.showError(e.message)}}showStatus(){let d=document.getElementById('pytml-status');if(!d){d=document.createElement('div');d.id='pytml-status';d.style.cssText='position:fixed;bottom:10px;right:10px;background:#007acc;color:#fff;padding:8px 12px;border-radius:4px;font-size:12px;font-family:monospace;z-index:9999';d.textContent='PYTML: Loading Python (5-10s first time)...';document.body.appendChild(d)}}hideStatus(){const d=document.getElementById('pytml-status');if(d)d.remove()}showError(m){const d=document.createElement('div');d.style.cssText='position:fixed;top:10px;right:10px;background:#dc3545;color:#fff;padding:10px;border-radius:4px;font-size:12px;z-index:9999';d.textContent=`PYTML Error: ${m}`;document.body.appendChild(d);setTimeout(()=>d.remove(),5e3)}loadScript(s){return new Promise((r,j)=>{const t=document.createElement('script');t.src=s;t.onload=r;t.onerror=j;document.head.appendChild(t)})}async wait(){if(this.ready)return;return new Promise(r=>this.q.push(r))}async run(c,i={}){await this.wait();try{let e='';for(const[k,v]of Object.entries(i)){if(typeof v==='string'){e+=`${k}="${v.replace(/"/g,'\\"')}"\n`}else{e+=`${k}=${JSON.stringify(v)}\n`}}const r=await this.pyodide.runPythonAsync(`import sys\nfrom io import StringIO\no=sys.stdout\nsys.stdout=StringIO()\ntry:\n${e}\n${c}\n o=sys.stdout.getvalue()\nexcept Exception as ex:\n o=f"Error: {str(ex)}"\nfinally:\n sys.stdout=o\no`);return r}catch(e){return`Error: ${e.message}`}}collectInputs(e){const i={};const f=e.closest('[data-python-form]');if(f){const a=f.querySelectorAll('input, select, textarea');for(const el of a){if(el.name){let v=el.value;if(el.type==='number'){v=parseFloat(v)}else if(el.type==='checkbox'){v=el.checked}i[el.name]=v}}}return i}async processPage(){await this.wait();const t=document.querySelectorAll('[data-python-text]');for(const e of t){const c=e.getAttribute('data-python-text');const r=await this.run(`print(${c})`);if(e)e.textContent=r.trim()}const h=document.querySelectorAll('[data-python-html]');for(const e of h){const c=e.getAttribute('data-python-html');const r=await this.run(`print(${c})`);if(e)e.innerHTML=r.trim()}const b=document.querySelectorAll('[data-python]');for(const btn of b){const c=btn.getAttribute('data-python');const t=btn.getAttribute('data-target');btn.addEventListener('click',async()=>{const i=this.collectInputs(btn);const r=await this.run(c,i);if(t){const te=document.querySelector(t);if(te){te.textContent=r}}})}}}w.pytml=new P})(window);
